const form = $input.first().json;
const metrics = form['Key Metrics (comma-separated)'] ? form['Key Metrics (comma-separated)'].split(',').map(m => m.trim()) : [];
return [{ json: { body: { contentType: form['Content Type'] || 'technical-walkthrough', transcript: form['Transcript'], videoUrl: form['Video URL'] || '', speakerName: form['Speaker Name'] || '', company: form['Company'] || '', metrics, title: (form['Speaker Name'] || 'Untitled') + ' — ' + (form['Content Type'] || 'B-Roll') } } }];

const body = $input.first().json.body;
const contentType = body.contentType || 'technical-walkthrough';
const FLOWS = {
  'technical-walkthrough': '5 scenes: Hook(big-stat-reveal) -> Speaker(person-scorecard) -> HowItWorks(workflow-pipeline) -> Results(data-table/kpi-dashboard) -> Arch+CTA(node-graph+cta-comment)',
  'case-study': '6 scenes: HookStat(big-stat-reveal) -> ClientIntro(person-scorecard) -> Challenge(comparison-split) -> Solution(timeline-steps) -> Results(kpi-dashboard) -> Trust+CTA(logo-endorsement+cta-comment)',
  'podcast': '4-6 scenes: GuestIntro(person-scorecard) -> KeyStat(big-stat-reveal) -> TopicViz(varies) -> CTA(cta-comment)'
};
const systemPrompt = `B-roll scene generator for CUTAWAY format. Output JSON: { "meta": { "contentType": "${contentType}", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "${body.videoUrl || ''}" }, "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...} }], "textStrip": { "labels": [...] } }

Flow: ${FLOWS[contentType]}

ASSET HINTS: workflow-pipeline/node-graph nodes can have icon: "mdi:database". logo-endorsement logos: just set name (Brandfetch fills imageUrl). backgroundVideo.query: triggers Pexels enrichment.

DIAGNOSTIC: durationInFrames 180-360 (6-12s). Adjacent scenes overlap 16+ frames. Percentages>95 need tickRange. No empty comparison-split sides. Realistic numbers.

Types: big-stat-reveal({value,prefix?,suffix?,color,subtitle}), person-scorecard({name,title,badges[{value,label}]}), kpi-dashboard({header,cards[{label,value,color,tickRange?}]}), workflow-pipeline({header,rows[[{label,sub?,glow?,icon?}]]}), data-table({header,table:{columns,rows}}), node-graph({header,nodes[{label,x,y,color,icon?}],edges[{from,to}]}), timeline-steps({header,steps[{label,status}]}), comparison-split({left:{header,color,icon,items},right:{header,color,icon,items}}), logo-endorsement({header,logos[{name,imageUrl?}]}), cta-comment({action,keyword})

frame=sec*30. Colors: #00D4FF #00FF88 #FF4444 #FF8C00 #8B5CF6. Output ONLY JSON.`;
const context = [body.speakerName ? `Speaker: ${body.speakerName}` : '', body.company ? `Company: ${body.company}` : '', body.metrics?.length ? `Metrics: ${body.metrics.join(', ')}` : ''].filter(Boolean).join('
');
const userMessage = `${context ? context + '

' : ''}Transcript:
${body.transcript}`;
return [{ json: { systemPrompt, userMessage, contentType, videoUrl: body.videoUrl || '', title: body.title || 'Untitled' } }];

const prev = $('Build Claude Prompt').first().json;
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || response.content?.[0]?.text || '';
let config;
try { config = JSON.parse(content); }
catch (e) { const m = content.match(/\{[\s\S]*\}/); if (m) config = JSON.parse(m[0]); else throw new Error('Failed to parse: ' + content.substring(0, 300)); }
const totalFrames = config.scenes.reduce((max, s) => Math.max(max, s.from + s.durationInFrames), 0);
if (!config.meta || !config.scenes?.length) throw new Error('Invalid config');
return [{ json: { config, totalFrames, totalSeconds: (totalFrames / 30).toFixed(1), sceneCount: config.scenes.length, sceneTypes: config.scenes.map(s => s.type), title: prev.title, contentType: prev.contentType, generatedAt: new Date().toISOString() } }];
